/* Journey Section */
.journey-timeline {
    position: relative;
    max-width: 1200px;
    margin: 0 auto;
}

.journey-timeline::after {
    content: '';
    position: absolute;
    width: 3px;
    background: var(--bs-primary);
    top: 0;
    bottom: 0;
    left: 50%;
    margin-left: -1.5px;
}

.journey-item {
    padding: 20px;
    position: relative;
    width: 50%;
    opacity: 0;
    transform: translateY(20px);
    transition: opacity 0.6s ease-out, transform 0.6s ease-out;
}

.journey-item::before {
    content: '';
    position: absolute;
    width: 16px;
    height: 16px;
    border-radius: 50%;
    background: var(--bs-primary);
    top: 24px;
}

.journey-item:nth-child(odd) {
    left: 0;
    padding-right: 40px;
}

.journey-item:nth-child(even) {
    left: 50%;
    padding-left: 40px;
}

.journey-item:nth-child(odd)::before {
    right: -8px;
}

.journey-item:nth-child(even)::before {
    left: -8px;
}

@media (max-width: 768px) {
    /* Move vertical line to the left edge */
    .journey-timeline::after {
        left: 20px;
        width: 2px;
    }

    /* All items stack in a single column */
    .journey-item,
    .journey-item:nth-child(odd),
