        width: 100%;
        left: 0;
        padding-left: 52px;
        padding-right: 12px;
        padding-top: 12px;
        padding-bottom: 12px;
    }

    /* Dot sits on the left line */
    .journey-item::before,
    .journey-item:nth-child(odd)::before,
