    .journey-item p {
        font-size: 0.88rem;
        margin-bottom: 0;
    }
}

.journey-item.animate {
    opacity: 1;
    transform: translateY(0);
}

/* Removed transition delays for immediate animation */

.journey-year {
    font-weight: bold;
    color: var(--bs-primary);
    margin-bottom: 5px;
}

