/* Journey Section */
.journey-subtitle {
    text-align: center;
    color: rgba(128,128,128,0.8);
    margin-bottom: 40px;
    font-size: 0.95rem;
}

.journey-timeline {
    position: relative;
    max-width: 1100px;
    margin: 0 auto;
    padding-bottom: 20px;
}

.journey-timeline::after {
    content: '';
    position: absolute;
    width: 2px;
    background: rgba(var(--bs-primary-rgb), 0.35);
    top: 0;
    bottom: 0;
    left: 50%;
    transform: translateX(-50%);
}

/* Each item */
.journey-item {
    position: relative;
    width: 45%;
    margin-bottom: 40px;
    opacity: 0;
    transition: opacity 0.3s ease, transform 0.3s ease;
}

.journey-item:nth-child(odd) {
    left: 0;
    transform: perspective(800px) rotateY(-80deg);
    transform-origin: right center;
}

.journey-item:nth-child(even) {
    left: 55%;
    transform: perspective(800px) rotateY(80deg);
    transform-origin: left center;
}

.journey-item.animate {
    opacity: 1;
    transform: perspective(800px) rotateY(0deg) !important;
}

/* Date badge on the center line */
.journey-badge {
    position: absolute;
    top: 16px;
    background: var(--bs-primary);
    color: #fff;
    font-size: 0.72rem;
    font-weight: 600;
    padding: 4px 10px;
    border-radius: 20px;
    white-space: nowrap;
    z-index: 2;
}

.journey-item:nth-child(odd) .journey-badge {
    right: -80px;
    transform: translateX(50%);
}

.journey-item:nth-child(even) .journey-badge {
    left: -80px;
    transform: translateX(-50%);
}

/* Card style */
.journey-card {
    background: rgba(var(--bs-primary-rgb), 0.05);
    border: 1px solid rgba(var(--bs-primary-rgb), 0.2);
    border-radius: 10px;
    padding: 18px 20px;
}

body:not(.dark-mode) .journey-card {
    background: #ffffff;
    border: 1px solid #e0e0e0;
    box-shadow: 0 2px 12px rgba(0,0,0,0.06);
}

.journey-card-header h4 {
    font-size: 1rem;
    font-weight: 700;
    margin-bottom: 4px;
}

.journey-company {
    font-size: 0.85rem;
    color: rgba(128,128,128,0.85);
    margin-bottom: 0;
}

.journey-divider {
    margin: 10px 0;
    border-color: rgba(var(--bs-primary-rgb), 0.2);
}

.journey-hl-title {
    font-size: 0.78rem;
    font-weight: 700;
    color: var(--bs-primary);
    margin-bottom: 6px;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.journey-hl {
    padding-left: 16px;
    margin-bottom: 0;
    font-size: 0.82rem;
    color: rgba(128,128,128,0.9);
}

.journey-hl li {
    margin-bottom: 3px;
}

/* Mobile */
@media (max-width: 768px) {
    .journey-timeline::after {
        left: 14px;
    }

    .journey-item,
    .journey-item:nth-child(odd),
    .journey-item:nth-child(even) {
        width: 100%;
        left: 0;
        padding-left: 36px;
        margin-bottom: 16px;
    }

    .journey-item:nth-child(odd) {
        transform: perspective(800px) rotateY(-80deg);
        transform-origin: right center;
    }

    .journey-item:nth-child(even) {
        transform: perspective(800px) rotateY(80deg);
        transform-origin: left center;
    }

    .journey-badge,
    .journey-item:nth-child(odd) .journey-badge,
